/**
 * @fileoverview ResourceList — explorer-style dense semantic table JIT parts.
 * @module module/ResourceList/constants
 */
import { defineParts } from '../shared/definePart.js';

/** Semantic part names for JIT styling overrides. */
export const PART = defineParts('ResourceList', {
    CONTAINER: { class: 'resource-list-container', aliases: ['container', 'root'] },
    WRAPPER: { class: 'resource-list-wrapper', aliases: ['wrapper'] },
    TABLE: { class: 'resource-list-table', aliases: ['table'] },
    THEAD: { class: 'resource-list-thead', aliases: ['thead'] },
    THEAD_TH: { class: 'resource-list-th', aliases: ['th', 'header-cell'] },
    SORT_ICON: { class: 'resource-list-sort-icon', aliases: ['sort-icon'] },
    TBODY_TR: { class: 'resource-list-row', aliases: ['row', 'tr'] },
    TBODY_TD: { class: 'resource-list-td', aliases: ['td', 'body-cell'] },
    EMPTY_ROW: { class: 'resource-list-empty-row', aliases: ['empty-row'] },
});

PART.CONTAINER.jit = [
    'relative rounded-[var(--rl-radius)] [border:none] bg-[var(--rl-bg)] fg-[var(--rl-text)] overflow-hidden text-[var(--rl-font-size)]',
].join(' ');
PART.WRAPPER.jit = '[overflow-x:auto] [overflow-y:visible]';
PART.TABLE.jit = 'w-full [border-collapse:separate] [border-spacing:0_4px] [table-layout:fixed] [font-size:inherit]';
PART.THEAD.jit = 'sticky [top:0] [z-index:2]';
PART.THEAD_TH.jit = [
    'relative [padding:var(--rl-header-py)_var(--rl-cell-px)] text-[var(--rl-header-font-size)] fw-[var(--rl-header-font-weight)] fg-[var(--rl-text-muted)] bg-[var(--rl-bg)] [text-align:left] text-nowrap [border-bottom:1px_solid_var(--rl-border)] [user-select:none]',
    '{is-sortable}:cursor-pointer {is-sortable}:hover:bg-[var(--rl-hover-header)]',
    '{is-sortable}:[padding-right:1.35rem]',
    '[&_.resource-list-sort-icon]:{is-sort-asc}:[opacity:1] [&_.resource-list-sort-icon]:{is-sort-desc}:[opacity:1]',
].join(' ');
PART.SORT_ICON.jit = 'absolute [right:0.25rem] [top:50%] [transform:translateY(-50%)] inline-flex items-center [opacity:0.35]';
PART.TBODY_TR.jit = [
    'resource-list-row outline-none rounded-[var(--rl-row-radius)]',
    '[transition:background-color_0.14s_ease]',
    '[&:hover_td]:bg-[var(--rl-hover-row-bg)]',
    '[&.is-selected_td]:bg-[var(--rl-selected-row-bg)]',
    '{is-selectable}:cursor-pointer',
].join(' ');
PART.TBODY_TD.jit = [
    '[padding:var(--rl-cell-py)_var(--rl-cell-px)] [vertical-align:middle] bg-transparent fg-[var(--rl-text)]',
    '[border-bottom:none]',
    'first:[border-top-left-radius:var(--rl-row-radius)] first:[border-bottom-left-radius:var(--rl-row-radius)]',
    'last:[border-top-right-radius:var(--rl-row-radius)] last:[border-bottom-right-radius:var(--rl-row-radius)]',
    '{is-nowrap}:text-nowrap {is-ellipsis}:text-nowrap {is-ellipsis}:overflow-hidden {is-ellipsis}:[text-overflow:ellipsis]',
].join(' ');
PART.EMPTY_ROW.jit = '[&_td]:[text-align:center] [&_td]:fg-[var(--rl-text-muted)] [&_td]:[padding:2rem_1rem] [&_td]:[font-style:italic]';
