/**
 * @fileoverview ResourceList barrel — explorer-style resource table.
 *
 * @module module/ResourceList
 */
import { default as razyui } from '../index.js';
import { ResourceListDef as DEF } from './ResourceList.def.js';
import ResourceList from './ResourceList/index.js';

razyui.ResourceList = ResourceList;

if (razyui.JIT?.defineComponent) {
    razyui.JIT.defineComponent(DEF.name, DEF);
}

export async function registerElement() {
    const ce = await razyui.ce?.();
    ce?.registerFromDef?.(DEF, ResourceList);
}

export default ResourceList;

export const stylesheet = null;
