/**
 * @fileoverview ResourceList component definition for JIT pipeline.
 *
 * Multi-project explorer-style resource table: roomy rows, no row borders,
 * optional sort headers and row selection ({@code single} | {@code multiple}).
 *
 * @module module/ResourceList.def
 */

import { PART } from './ResourceList/constants.js';

export const ResourceListDef = {
    name: 'ResourceList',
    tag: 'rui-resource-list',

    tokens: {
        prefix: 'rl',
        tokens: {
            radius: { ref: 'radius.md', description: 'Outer container radius' },
            'row-radius': { ref: 'radius.sm', description: 'Selected / hover row corner radius' },
            bg: { ref: 'color.bg', description: 'Surface background' },
            border: { ref: 'color.border', description: 'Header underline' },
            text: { ref: 'color.text', description: 'Primary text' },
            'text-muted': { ref: 'color.text-muted', description: 'Header label / empty state' },
            accent: { ref: 'color.accent', description: 'Accent (selection tint anchor)' },
            'hover-header': { ref: 'color.bg-hover', description: 'Sortable header hover' },
            'hover-row-bg': { ref: 'color.bg-hover', description: 'Row hover fill' },
            'selected-row-bg': {
                value: 'color-mix(in srgb, var(--rl-accent, var(--color-accent, #6366f1)) 12%, var(--rl-bg, var(--color-bg, #fff)))',
                description: 'Selected row background',
            },
            'font-size': { value: '0.875rem', description: 'Body cell font size' },
            'header-font-size': { value: '0.75rem', description: 'Header font size' },
            'header-font-weight': { value: '600', description: 'Header weight' },
            'cell-px': { ref: 'spacing.3', description: 'Horizontal cell padding' },
            'cell-py': { ref: 'spacing.4', description: 'Vertical cell padding' },
            'header-py': { ref: 'spacing.3', description: 'Header vertical padding' },
        },
    },

    states: {
        initial: 'idle',
        states: { idle: {} },
    },

    template: {
        slots: {
            root: { element: 'div', classes: ['resource-list-container'] },
            table: { element: 'table', classes: ['resource-list-table'] },
            thead: { element: 'thead', classes: [] },
            tbody: { element: 'tbody', classes: [] },
        },
    },

    jitParts: {
        [PART.CONTAINER]: PART.CONTAINER,
        [PART.WRAPPER]: PART.WRAPPER,
        [PART.TABLE]: PART.TABLE,
        [PART.THEAD]: PART.THEAD,
        [PART.THEAD_TH]: PART.THEAD_TH,
        [PART.SORT_ICON]: PART.SORT_ICON,
        [PART.TBODY_TR]: PART.TBODY_TR,
        [PART.TBODY_TD]: PART.TBODY_TD,
        [PART.EMPTY_ROW]: PART.EMPTY_ROW,
    },

    styles: {},

    observedAttrs: ['data', 'columns', 'selection', 'row-id-key', 'empty-message'],

    attrMap: {
        data: 'data',
        columns: 'columns',
        selection: 'selection',
        'row-id-key': 'rowIdKey',
        'empty-message': 'emptyMessage',
    },
};

export default ResourceListDef;
